export const WebsiteLibraryView: React.FC = () => {
  const { showToast } = useToast();

  // State
  const [websites, setWebsites] = useState<LibraryWebsite[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [industryFilter, setIndustryFilter] = useState<WebsiteIndustry | 'all'>('all');

  // Selected website for detail view
  const [selectedWebsite, setSelectedWebsite] = useState<LibraryWebsite | null>(null);

  // Modal states
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [websiteToDelete, setWebsiteToDelete] = useState<LibraryWebsite | null>(null);
  const [showPreviewModal, setShowPreviewModal] = useState(false);
  const [previewWebsite, setPreviewWebsite] = useState<LibraryWebsite | null>(null);

  // Page management
  const [showAddPageModal, setShowAddPageModal] = useState(false);
  const [editingPage, setEditingPage] = useState<WebsitePage | null>(null);
  const [pageToDelete, setPageToDelete] = useState<WebsitePage | null>(null);
  const [showDeletePageConfirm, setShowDeletePageConfirm] = useState(false);
  const [newPageForm, setNewPageForm] = useState({ name: '', url: '' });
  const [draggedPageId, setDraggedPageId] = useState<string | null>(null);

  // Lock state for page preview cards (per page ID)
  const [unlockedPageCards, setUnlockedPageCards] = useState<Set<string>>(new Set());

  // Edit website state
  const [editingWebsite, setEditingWebsite] = useState<LibraryWebsite | null>(null);

  // Form state for add/edit website
  const [websiteForm, setWebsiteForm] = useState({
    name: '',
    liveUrl: '',
    industry: 'other' as WebsiteIndustry,
    notes: '',
    previewMode: 'live' as WebsitePreviewMode,
    thumbnail: '',
  });

  // Lock state for scrollable iframes (per website ID)
  const [unlockedCards, setUnlockedCards] = useState<Set<string>>(new Set());

  // Load websites from localStorage
  useEffect(() => {
    try {
      const saved = localStorage.getItem('tawfeeq_website_library');
      if (saved) {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setWebsites(parsed);
          setIsLoading(false);
          return;
        }
      }
    } catch (e) {
      console.error('Error loading websites:', e);
      localStorage.removeItem('tawfeeq_website_library');
    }
    // Use defaults
    const defaults = getDefaultWebsites();
    localStorage.setItem('tawfeeq_website_library', JSON.stringify(defaults));
    setWebsites(defaults);
    setIsLoading(false);
  }, []);

  // Auto-save websites
  useEffect(() => {
    if (!isLoading && websites.length > 0) {
      localStorage.setItem('tawfeeq_website_library', JSON.stringify(websites));
    }
  }, [websites, isLoading]);

  // Get snapshots for linking
  const snapshots = React.useMemo(() => {
    try {
      const saved = localStorage.getItem('tawfeeq_snapshots');
      if (saved) {
        return JSON.parse(saved) as Snapshot[];
      }
    } catch (e) {
      console.error('Error loading snapshots:', e);
    }
    return [];
  }, []);

  // Filter websites
  const filteredWebsites = React.useMemo(() => {
    return websites.filter(website => {
      const matchesSearch = searchQuery === '' ||
        website.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        website.liveUrl.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesIndustry = industryFilter === 'all' || website.industry === industryFilter;
      return matchesSearch && matchesIndustry;
    });
  }, [websites, searchQuery, industryFilter]);

  // Get industry info
  const getIndustryInfo = (industryId: string) => {
    return WEBSITE_INDUSTRIES.find(i => i.id === industryId) || WEBSITE_INDUSTRIES[WEBSITE_INDUSTRIES.length - 1];
  };

  // Get linked snapshot names
  const getLinkedSnapshotNames = (website: LibraryWebsite) => {
    return website.linkedSnapshotIds
      .map(id => snapshots.find(s => s.id === id)?.name)
      .filter(Boolean)
      .join(', ');
  };

  // Toggle lock/unlock for a card
  const toggleCardLock = (websiteId: string) => {
    setUnlockedCards(prev => {
      const next = new Set(prev);
      if (next.has(websiteId)) {
        next.delete(websiteId);
      } else {
        next.add(websiteId);
      }
      return next;
    });
  };

  // Toggle lock/unlock for a page card
  const togglePageCardLock = (pageId: string) => {
    setUnlockedPageCards(prev => {
      const next = new Set(prev);
      if (next.has(pageId)) {
        next.delete(pageId);
      } else {
        next.add(pageId);
      }
      return next;
    });
  };

  // Handle add website
  const handleAddWebsite = () => {
    if (!websiteForm.name.trim()) {
      showToast('error', 'Please enter a website name');
      return;
    }

    // Auto-create Home page with the website's main URL
    const liveUrl = websiteForm.liveUrl.trim();
    const homePageUrl = liveUrl || ''; // Use the main website URL as the Home page URL

    const newWebsite: LibraryWebsite = {
      id: generateId(),
      name: websiteForm.name.trim(),
      industry: websiteForm.industry,
      liveUrl: liveUrl,
      previewMode: websiteForm.previewMode,
      thumbnail: websiteForm.thumbnail.trim() || undefined,
      pages: [{ id: generateId(), name: 'Home', url: homePageUrl, order: 0, isHomePage: true }],
      linkedSnapshotIds: [],
      notes: websiteForm.notes.trim(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    setWebsites([...websites, newWebsite]);
    setShowAddModal(false);
    setWebsiteForm({ name: '', liveUrl: '', industry: 'other', notes: '', previewMode: 'live', thumbnail: '' });
    showToast('success', 'Website added to library');
  };

  // Handle update website
  const handleUpdateWebsite = () => {
    if (!editingWebsite || !websiteForm.name.trim()) {
      showToast('error', 'Please enter a website name');
      return;
    }

    const newLiveUrl = websiteForm.liveUrl.trim();

    // Update pages: if main URL changed, update the Home page URL as well
    const updatedPages = editingWebsite.pages.map(p =>
      p.isHomePage ? { ...p, url: newLiveUrl } : p
    );

    const updatedWebsites = websites.map(w =>
      w.id === editingWebsite.id
        ? {
            ...w,
            name: websiteForm.name.trim(),
            industry: websiteForm.industry,
            liveUrl: newLiveUrl,
            previewMode: websiteForm.previewMode,
            thumbnail: websiteForm.thumbnail.trim() || undefined,
            notes: websiteForm.notes.trim(),
            pages: updatedPages,
            updatedAt: new Date().toISOString(),
          }
        : w
    );

    setWebsites(updatedWebsites);

    // Update selected website if it's the one being edited
    if (selectedWebsite?.id === editingWebsite.id) {
      setSelectedWebsite({
        ...selectedWebsite,
        name: websiteForm.name.trim(),
        industry: websiteForm.industry,
        liveUrl: newLiveUrl,
        previewMode: websiteForm.previewMode,
        thumbnail: websiteForm.thumbnail.trim() || undefined,
        notes: websiteForm.notes.trim(),
        pages: updatedPages,
        updatedAt: new Date().toISOString(),
      });
    }

    setEditingWebsite(null);
    setShowAddModal(false);
    setWebsiteForm({ name: '', liveUrl: '', industry: 'other', notes: '', previewMode: 'live', thumbnail: '' });
    showToast('success', 'Website updated');
  };

  // Handle delete website
  const handleDeleteWebsite = () => {
    if (!websiteToDelete) return;
    setWebsites(websites.filter(w => w.id !== websiteToDelete.id));
    if (selectedWebsite?.id === websiteToDelete.id) {
      setSelectedWebsite(null);
    }
    setWebsiteToDelete(null);
    setShowDeleteConfirm(false);
    showToast('success', 'Website removed from library');
  };

  // Handle duplicate website
  const handleDuplicateWebsite = (website: LibraryWebsite) => {
    const duplicate: LibraryWebsite = {
      ...website,
      id: generateId(),
      name: `${website.name} (copy)`,
      pages: website.pages.map(p => ({ ...p, id: generateId() })),
      linkedSnapshotIds: [],
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
    setWebsites([...websites, duplicate]);
    showToast('success', 'Website duplicated');
  };

  // Page management handlers
  const handleAddPage = () => {
    if (!selectedWebsite || !newPageForm.name.trim()) {
      showToast('error', 'Please enter a page name');
      return;
    }

    if (!newPageForm.url.trim()) {
      showToast('error', 'Please enter a page URL');
      return;
    }

    const newPage: WebsitePage = {
      id: generateId(),
      name: newPageForm.name.trim(), // Internal label only
      url: newPageForm.url.trim(), // Full URL (e.g., https://site.com/about)
      order: selectedWebsite.pages.length,
      isHomePage: false,
    };

    const updatedPages = [...selectedWebsite.pages, newPage];
    const updatedWebsites = websites.map(w =>
      w.id === selectedWebsite.id
        ? { ...w, pages: updatedPages, updatedAt: new Date().toISOString() }
        : w
    );

    setWebsites(updatedWebsites);
    setSelectedWebsite({ ...selectedWebsite, pages: updatedPages });
    setShowAddPageModal(false);
    setNewPageForm({ name: '', url: '' });
    showToast('success', 'Page added');
  };

  const handleUpdatePage = () => {
    if (!selectedWebsite || !editingPage || !newPageForm.name.trim()) {
      showToast('error', 'Please enter a page name');
      return;
    }

    // For home page, URL cannot be changed (synced with main website URL)
    // For other pages, require URL
    if (!editingPage.isHomePage && !newPageForm.url.trim()) {
      showToast('error', 'Please enter a page URL');
      return;
    }

    const updatedPages = selectedWebsite.pages.map(p =>
      p.id === editingPage.id
        ? {
            ...p,
            name: newPageForm.name.trim(),
            // Keep home page URL synced with main website URL, otherwise use form value
            url: p.isHomePage ? p.url : newPageForm.url.trim(),
          }
        : p
    );

    const updatedWebsites = websites.map(w =>
      w.id === selectedWebsite.id
        ? { ...w, pages: updatedPages, updatedAt: new Date().toISOString() }
        : w
    );

    setWebsites(updatedWebsites);
    setSelectedWebsite({ ...selectedWebsite, pages: updatedPages });
    setEditingPage(null);
    setShowAddPageModal(false);
    setNewPageForm({ name: '', url: '' });
    showToast('success', 'Page updated');
  };

  const handleDeletePage = () => {
    if (!selectedWebsite || !pageToDelete) return;

    // Cannot delete the home page
    if (pageToDelete.isHomePage) {
      showToast('error', 'Cannot delete the home page');
      setPageToDelete(null);
      setShowDeletePageConfirm(false);
      return;
    }

    const updatedPages = selectedWebsite.pages
      .filter(p => p.id !== pageToDelete.id)
      .map((p, idx) => ({ ...p, order: idx }));

    const updatedWebsites = websites.map(w =>
      w.id === selectedWebsite.id
        ? { ...w, pages: updatedPages, updatedAt: new Date().toISOString() }
        : w
    );

    setWebsites(updatedWebsites);
    setSelectedWebsite({ ...selectedWebsite, pages: updatedPages });
    setPageToDelete(null);
    setShowDeletePageConfirm(false);
    showToast('success', 'Page deleted');
  };

  const handleReorderPages = (dragId: string, dropId: string) => {
    if (!selectedWebsite || dragId === dropId) return;

    const pages = [...selectedWebsite.pages];
    const dragIndex = pages.findIndex(p => p.id === dragId);
    const dropIndex = pages.findIndex(p => p.id === dropId);

    if (dragIndex === -1 || dropIndex === -1) return;

    const [draggedPage] = pages.splice(dragIndex, 1);
    pages.splice(dropIndex, 0, draggedPage);

    // Update order
    const reorderedPages = pages.map((p, idx) => ({ ...p, order: idx }));

    const updatedWebsites = websites.map(w =>
      w.id === selectedWebsite.id
        ? { ...w, pages: reorderedPages, updatedAt: new Date().toISOString() }
        : w
    );

    setWebsites(updatedWebsites);
    setSelectedWebsite({ ...selectedWebsite, pages: reorderedPages });
  };

  // Pages now store full URLs directly, so just return the URL
  // This function is kept for any remaining references but is now simpler
  const getFullPageUrl = (page: WebsitePage) => {
    return page.url;
  };

  // Open edit modal
  const openEditModal = (website: LibraryWebsite) => {
    setEditingWebsite(website);
    setWebsiteForm({
      name: website.name,
      liveUrl: website.liveUrl,
      industry: website.industry,
      notes: website.notes || '',
    });
    setShowAddModal(true);
  };

  // Loading state
  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gold-500" />
      </div>
    );
  }

  // Detail view when a website is selected
  if (selectedWebsite) {
    const industry = getIndustryInfo(selectedWebsite.industry);
    const linkedSnapshots = getLinkedSnapshotNames(selectedWebsite);

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <button
            onClick={() => setSelectedWebsite(null)}
            className="flex items-center gap-2 text-gray-600 dark:text-dark-muted hover:text-gray-800 dark:hover:text-dark-text transition-colors"
          >
            <ArrowLeft size={18} />
            <span className="font-medium">Back to Library</span>
          </button>
          <div className="flex items-center gap-2">
            <button
              onClick={() => openEditModal(selectedWebsite)}
              className="flex items-center gap-1.5 px-3 py-1.5 border border-gray-200 dark:border-dark-border rounded-lg text-sm font-medium text-gray-700 dark:text-dark-text hover:bg-gray-50 dark:hover:bg-dark-elevated transition-colors"
            >
              <Edit3 size={14} />
              Edit
            </button>
            {selectedWebsite.liveUrl && (
              <a
                href={selectedWebsite.liveUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center gap-1.5 bg-gold-500 text-white px-3 py-1.5 rounded-lg text-sm font-medium hover:bg-gold-600 transition-colors"
              >
                <ExternalLink size={14} />
                Open Live Site
              </a>
            )}
          </div>
        </div>

        {/* Website info card */}
        <div className="bg-white dark:bg-dark-card rounded-xl border border-gray-200 dark:border-dark-border p-6">
          <div className="flex items-start gap-4">
            <div className={`w-14 h-14 ${industry.color} rounded-xl flex items-center justify-center text-2xl`}>
              {industry.icon}
            </div>
            <div className="flex-1 min-w-0">
              <h2 className="text-xl font-bold text-gray-800 dark:text-dark-text">{selectedWebsite.name}</h2>
              {selectedWebsite.liveUrl && (
                <a
                  href={selectedWebsite.liveUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-sm text-gold-600 dark:text-gold-400 hover:text-gold-700 flex items-center gap-1 mt-1"
                >
                  <Globe size={14} />
                  {selectedWebsite.liveUrl.replace(/^https?:\/\//, '')}
                </a>
              )}
              <div className="flex items-center gap-3 mt-2">
                <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium ${industry.color} text-white`}>
                  {industry.icon} {industry.name}
                </span>
                <span className="text-sm text-gray-500 dark:text-dark-muted">
                  {selectedWebsite.pages.length} pages
                </span>
              </div>
              {linkedSnapshots && (
                <div className="mt-2 flex items-center gap-2 text-sm text-gray-500 dark:text-dark-muted">
                  <Layers size={14} />
                  Linked to: {linkedSnapshots}
                </div>
              )}
              {selectedWebsite.notes && (
                <p className="mt-3 text-sm text-gray-600 dark:text-dark-muted">{selectedWebsite.notes}</p>
              )}
            </div>
          </div>
        </div>

        {/* Pages section */}
        <div className="bg-white dark:bg-dark-card rounded-xl border border-gray-200 dark:border-dark-border overflow-hidden">
          <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 dark:border-dark-border">
            <h3 className="font-semibold text-gray-800 dark:text-dark-text">
              Pages ({selectedWebsite.pages.length})
            </h3>
            <button
              onClick={() => {
                setEditingPage(null);
                setNewPageForm({ name: '', url: '' });
                setShowAddPageModal(true);
              }}
              className="flex items-center gap-1.5 text-gold-600 dark:text-gold-400 hover:text-gold-700 text-sm font-medium transition-colors"
            >
              <Plus size={16} />
              Add Page
            </button>
          </div>

          <div className="p-6">
            {selectedWebsite.pages.length === 0 ? (
              <div className="text-center py-8 bg-gray-50 dark:bg-dark-elevated rounded-xl border-2 border-dashed border-gray-200 dark:border-dark-border">
                <FileText size={32} className="text-gray-400 mx-auto mb-2" />
                <p className="text-gray-500 dark:text-dark-muted mb-3">No pages yet</p>
                <button
                  onClick={() => {
                    setEditingPage(null);
                    setNewPageForm({ name: '', url: '' });
                    setShowAddPageModal(true);
                  }}
                  className="inline-flex items-center gap-1.5 bg-gold-500 text-white px-3 py-1.5 rounded-lg text-sm font-medium hover:bg-gold-600 transition-colors"
                >
                  <Plus size={14} />
                  Add First Page
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {selectedWebsite.pages
                  .sort((a, b) => a.order - b.order)
                  .map((page, index) => {
                    const isPageUnlocked = unlockedPageCards.has(page.id);
                    const hasPageUrl = !!page.url; // Each page stores its own full URL
                    const fullPageUrl = page.url; // Direct URL, no concatenation needed

                    return (
                      <div
                        key={page.id}
                        draggable={!isPageUnlocked}
                        onDragStart={() => !isPageUnlocked && setDraggedPageId(page.id)}
                        onDragEnd={() => setDraggedPageId(null)}
                        onDragOver={(e) => e.preventDefault()}
                        onDrop={() => {
                          if (draggedPageId && draggedPageId !== page.id) {
                            handleReorderPages(draggedPageId, page.id);
                          }
                        }}
                        className={`group relative rounded-xl overflow-hidden bg-white dark:bg-dark-card border shadow-sm transition-all duration-300 ${
                          draggedPageId === page.id
                            ? 'opacity-50 border-gold-400'
                            : !isPageUnlocked
                              ? 'border-gray-200 dark:border-dark-border hover:shadow-xl hover:border-gold-300 dark:hover:border-gold-600'
                              : 'border-gray-200 dark:border-dark-border'
                        }`}
                      >
                        {/* Drag handle */}
                        {!isPageUnlocked && (
                          <div className="absolute top-2 left-2 z-10 p-1 bg-white/90 dark:bg-dark-card/90 rounded text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
                            <GripVertical size={14} />
                          </div>
                        )}

                        {/* Preview area - 16:10 aspect ratio for website previews */}
                        <div
                          className="relative aspect-[16/10] bg-gradient-to-br from-gray-100 to-gray-50 dark:from-gray-800 dark:to-gray-900 overflow-hidden"
                          style={{ cursor: isPageUnlocked ? 'default' : 'pointer' }}
                        >
                          {/* Live iframe preview */}
                          {hasPageUrl ? (
                            <div
                              className="absolute inset-0"
                              style={{
                                overflow: isPageUnlocked ? 'auto' : 'hidden',
                                pointerEvents: isPageUnlocked ? 'auto' : 'none',
                              }}
                            >
                              {/*
                                Structure:
                                - Outer div: clips content, handles scroll (overflow)
                                - Inner div: sized to scaled dimensions so scrollbar knows content size
                                - Iframe: full 1440x3000, visually scaled to 0.28

                                Lock/unlock ONLY toggles overflow + pointerEvents.
                                Scale, dimensions, transform-origin stay constant.
                              */}
                              <div style={{ width: '403px', height: '840px', position: 'relative' }}>
                                <iframe
                                  src={fullPageUrl}
                                  title={page.name}
                                  style={{
                                    position: 'absolute',
                                    top: 0,
                                    left: 0,
                                    width: '1440px',
                                    height: '3000px',
                                    border: 'none',
                                    transform: 'scale(0.28)',
                                    transformOrigin: 'top left',
                                  }}
                                  sandbox="allow-scripts allow-same-origin"
                                />
                              </div>
                            </div>
                          ) : page.thumbnail ? (
                            /* Uploaded thumbnail */
                            <img
                              src={page.thumbnail}
                              alt={page.name}
                              className="w-full h-full object-cover object-top"
                            />
                          ) : (
                            /* Fallback placeholder */
                            <div className="absolute inset-0 flex items-center justify-center">
                              <div className="text-center">
                                <Monitor size={32} className="text-gray-400 mx-auto mb-2" />
                                <span className="text-sm text-gray-400">{page.url || '/'}</span>
                              </div>
                            </div>
                          )}

                          {/* Hover overlay - only show when locked */}
                          {!isPageUnlocked && (
                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-4">
                              {/* Page name and info */}
                              <div className="transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                                <h3 className="font-semibold text-white text-base truncate mb-1">{page.name}</h3>
                                <div className="flex items-center gap-2 mb-3">
                                  <span className="text-white/80 text-xs truncate">{page.url || '/'}</span>
                                  <span className="text-white/60 text-xs">#{index + 1}</span>
                                </div>
                              </div>

                              {/* Quick action icons */}
                              <div className="flex items-center gap-2 transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300 delay-75">
                                {hasPageUrl && (
                                  <a
                                    href={fullPageUrl}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    onClick={(e) => e.stopPropagation()}
                                    className="p-2 bg-white/20 hover:bg-white/30 rounded-lg backdrop-blur-sm transition-colors"
                                    title="Open Page"
                                  >
                                    <ExternalLink size={16} className="text-white" />
                                  </a>
                                )}
                                <button
                                  onClick={(e) => {
                                    e.stopPropagation();
                                    setEditingPage(page);
                                    setNewPageForm({ name: page.name, url: page.url });
                                    setShowAddPageModal(true);
                                  }}
                                  className="p-2 bg-white/20 hover:bg-white/30 rounded-lg backdrop-blur-sm transition-colors"
                                  title="Edit"
                                >
                                  <Edit3 size={16} className="text-white" />
                                </button>
                                {/* Only show delete button for non-home pages */}
                                {!page.isHomePage && (
                                  <button
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      setPageToDelete(page);
                                      setShowDeletePageConfirm(true);
                                    }}
                                    className="p-2 bg-white/20 hover:bg-red-500/50 rounded-lg backdrop-blur-sm transition-colors"
                                    title="Delete"
                                  >
                                    <Trash2 size={16} className="text-white" />
                                  </button>
                                )}
                              </div>
                            </div>
                          )}

                          {/* Lock/Unlock button - always visible in bottom right for live previews */}
                          {hasPageUrl && (
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                togglePageCardLock(page.id);
                              }}
                              className={`absolute bottom-3 right-3 p-2 rounded-lg shadow-lg transition-all z-10 ${
                                isPageUnlocked
                                  ? 'bg-gold-500 text-white hover:bg-gold-600'
                                  : 'bg-white/90 dark:bg-dark-card/90 text-gray-600 dark:text-dark-muted hover:bg-white dark:hover:bg-dark-card'
                              }`}
                              title={isPageUnlocked ? 'Lock scroll (click to lock)' : 'Unlock scroll (click to scroll through page)'}
                            >
                              {isPageUnlocked ? <Unlock size={16} /> : <Lock size={16} />}
                            </button>
                          )}
                        </div>

                        {/* Card footer - page name and URL */}
                        <div className="p-3 border-t border-gray-100 dark:border-dark-border">
                          <div className="flex items-center justify-between">
                            <div className="min-w-0">
                              <div className="flex items-center gap-2">
                                <h4 className="font-medium text-gray-800 dark:text-dark-text text-sm truncate">{page.name}</h4>
                                {page.isHomePage && (
                                  <span className="px-1.5 py-0.5 bg-gold-100 dark:bg-gold-900/30 text-gold-600 dark:text-gold-400 text-[10px] font-medium rounded">
                                    HOME
                                  </span>
                                )}
                              </div>
                              <p className="text-xs text-gray-500 dark:text-dark-muted truncate">{page.url || 'No URL'}</p>
                            </div>
                            <span className="text-xs text-gray-400 dark:text-dark-muted flex-shrink-0 ml-2">
                              #{index + 1}
                            </span>
                          </div>
                        </div>
                      </div>
                    );
                  })}

                {/* Add page card - matches page card styling */}
                <button
                  onClick={() => {
                    setEditingPage(null);
                    setNewPageForm({ name: '', url: '' });
                    setShowAddPageModal(true);
                  }}
                  className="group relative rounded-xl border-2 border-dashed border-gray-300 dark:border-dark-border hover:border-gold-400 dark:hover:border-gold-500 bg-gray-50/50 dark:bg-dark-elevated/50 flex items-center justify-center transition-all duration-300 hover:bg-gold-50/50 dark:hover:bg-gold-900/10 min-h-[240px]"
                >
                  <div className="flex flex-col items-center gap-3">
                    <div className="w-14 h-14 bg-gray-200 dark:bg-dark-border rounded-full flex items-center justify-center group-hover:bg-gold-100 dark:group-hover:bg-gold-900/30 transition-colors">
                      <Plus size={24} className="text-gray-500 group-hover:text-gold-600 dark:group-hover:text-gold-400 transition-colors" />
                    </div>
                    <span className="text-sm font-medium text-gray-500 group-hover:text-gold-600 dark:group-hover:text-gold-400 transition-colors">Add Page</span>
                  </div>
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Add/Edit Page Modal */}
        {showAddPageModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={() => setShowAddPageModal(false)}>
            <div
              className="bg-white dark:bg-dark-card rounded-xl shadow-xl w-full max-w-md mx-4"
              onClick={(e) => e.stopPropagation()}
            >
              <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-dark-border">
                <h3 className="font-semibold text-gray-800 dark:text-dark-text">
                  {editingPage ? (editingPage.isHomePage ? 'Edit Home Page' : 'Edit Page') : 'Add New Page'}
                </h3>
                <button
                  onClick={() => setShowAddPageModal(false)}
                  className="p-1 text-gray-400 hover:text-gray-600"
                >
                  <X size={20} />
                </button>
              </div>
              <div className="p-4 space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Page Name *</label>
                  <input
                    type="text"
                    value={newPageForm.name}
                    onChange={(e) => setNewPageForm({ ...newPageForm, name: e.target.value })}
                    placeholder="e.g., About Us, Services, Contact"
                    className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
                  />
                  <p className="text-xs text-gray-500 dark:text-dark-muted mt-1">Internal label for display in the CRM</p>
                </div>
                {/* Only show URL field for non-home pages */}
                {(!editingPage || !editingPage.isHomePage) && (
                  <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Page URL *</label>
                    <input
                      type="text"
                      value={newPageForm.url}
                      onChange={(e) => setNewPageForm({ ...newPageForm, url: e.target.value })}
                      placeholder="https://yoursite.com/about"
                      className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
                    />
                    <p className="text-xs text-gray-500 dark:text-dark-muted mt-1">Full URL to the page (e.g., https://site.com/about)</p>
                  </div>
                )}
                {/* Show info for home page URL */}
                {editingPage?.isHomePage && (
                  <div className="bg-gray-50 dark:bg-dark-elevated rounded-lg p-3">
                    <p className="text-xs text-gray-500 dark:text-dark-muted">
                      <span className="font-medium">URL:</span> {editingPage.url || 'Not set'}
                    </p>
                    <p className="text-xs text-gray-400 dark:text-dark-muted mt-1">
                      Home page URL is synced with the main website URL. Edit the website to change it.
                    </p>
                  </div>
                )}
              </div>
              <div className="flex gap-3 p-4 border-t border-gray-200 dark:border-dark-border">
                <button
                  onClick={() => setShowAddPageModal(false)}
                  className="flex-1 px-4 py-2 border border-gray-200 dark:border-dark-border rounded-lg text-gray-600 hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={editingPage ? handleUpdatePage : handleAddPage}
                  className="flex-1 px-4 py-2 bg-gold-500 text-white rounded-lg hover:bg-gold-600 transition-colors font-medium"
                >
                  {editingPage ? 'Save Changes' : 'Add Page'}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Delete Page Confirmation */}
        {showDeletePageConfirm && pageToDelete && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={() => setShowDeletePageConfirm(false)}>
            <div
              className="bg-white dark:bg-dark-card rounded-xl shadow-xl w-full max-w-sm mx-4 p-5"
              onClick={(e) => e.stopPropagation()}
            >
              <div className="text-center mb-4">
                <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-3">
                  <Trash2 size={24} className="text-red-500" />
                </div>
                <h3 className="font-semibold text-gray-800 dark:text-dark-text mb-1">Delete Page?</h3>
                <p className="text-sm text-gray-500">
                  Are you sure you want to delete "{pageToDelete.name}"?
                </p>
              </div>
              <div className="flex gap-3">
                <button
                  onClick={() => setShowDeletePageConfirm(false)}
                  className="flex-1 px-4 py-2 border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={handleDeletePage}
                  className="flex-1 px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors font-medium"
                >
                  Delete
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  // Main library grid view
  return (
    <div className="space-y-6">
      {/* Header with search and filter */}
      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
        <div className="flex-1 flex items-center gap-4">
          {/* Search */}
          <div className="relative flex-1 max-w-md">
            <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search websites..."
              className="w-full pl-10 pr-4 py-2.5 border border-gray-200 dark:border-dark-border rounded-xl bg-white dark:bg-dark-card text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
            />
          </div>

          {/* Industry filter */}
          <select
            value={industryFilter}
            onChange={(e) => setIndustryFilter(e.target.value as WebsiteIndustry | 'all')}
            className="px-4 py-2.5 border border-gray-200 dark:border-dark-border rounded-xl bg-white dark:bg-dark-card text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
          >
            <option value="all">All Industries</option>
            {WEBSITE_INDUSTRIES.map(ind => (
              <option key={ind.id} value={ind.id}>{ind.icon} {ind.name}</option>
            ))}
          </select>
        </div>

        {/* Add website button */}
        <button
          onClick={() => {
            setEditingWebsite(null);
            setWebsiteForm({ name: '', liveUrl: '', industry: 'other', notes: '' });
            setShowAddModal(true);
          }}
          className="flex items-center gap-2 bg-gold-500 text-white px-4 py-2.5 rounded-xl font-medium hover:bg-gold-600 transition-colors shadow-sm"
        >
          <Plus size={18} />
          Add Website
        </button>
      </div>

      {/* Website count */}
      <div className="text-sm text-gray-500 dark:text-dark-muted">
        {filteredWebsites.length} website{filteredWebsites.length !== 1 ? 's' : ''} in library
      </div>

      {/* Website grid */}
      {filteredWebsites.length === 0 ? (
        <div className="bg-white dark:bg-dark-card rounded-xl border border-gray-200 dark:border-dark-border p-12 text-center">
          <div className="w-20 h-20 mx-auto bg-gold-50 dark:bg-gold-900/30 rounded-full flex items-center justify-center mb-4">
            <Globe size={32} className="text-gold-500" />
          </div>
          <h3 className="text-lg font-semibold text-gray-800 dark:text-dark-text mb-2">
            {searchQuery || industryFilter !== 'all' ? 'No websites found' : 'No websites yet'}
          </h3>
          <p className="text-gray-500 dark:text-dark-muted mb-4">
            {searchQuery || industryFilter !== 'all'
              ? 'Try adjusting your search or filter'
              : 'Add your first website template to the library'}
          </p>
          {!searchQuery && industryFilter === 'all' && (
            <button
              onClick={() => {
                setEditingWebsite(null);
                setWebsiteForm({ name: '', liveUrl: '', industry: 'other', notes: '' });
                setShowAddModal(true);
              }}
              className="inline-flex items-center gap-2 bg-gold-500 text-white px-4 py-2 rounded-lg font-medium hover:bg-gold-600 transition-colors"
            >
              <Plus size={18} />
              Add Website
            </button>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredWebsites.map(website => {
            const industry = getIndustryInfo(website.industry);
            const isUnlocked = unlockedCards.has(website.id);
            const useLivePreview = website.previewMode === 'live' && website.liveUrl;

            return (
              <div
                key={website.id}
                className={`group relative rounded-xl overflow-hidden bg-white dark:bg-dark-card border border-gray-200 dark:border-dark-border shadow-sm transition-all duration-300 ${!isUnlocked ? 'hover:shadow-xl hover:border-gold-300 dark:hover:border-gold-600' : ''}`}
              >
                {/* Preview area - 16:10 aspect ratio for website previews */}
                <div
                  className="relative aspect-[16/10] bg-gradient-to-br from-gray-100 to-gray-50 dark:from-gray-800 dark:to-gray-900 overflow-hidden"
                  onClick={() => !isUnlocked && setSelectedWebsite(website)}
                  style={{ cursor: isUnlocked ? 'default' : 'pointer' }}
                >
                  {/* Live iframe preview - scaled down to show full desktop view */}
                  {useLivePreview ? (
                    <div
                      className="absolute inset-0"
                      style={{
                        overflow: isUnlocked ? 'auto' : 'hidden',
                        pointerEvents: isUnlocked ? 'auto' : 'none',
                      }}
                    >
                      {/*
                        Structure:
                        - Outer div: clips content, handles scroll (overflow)
                        - Inner div: sized to scaled dimensions (403x840) so scrollbar knows content size
                        - Iframe: full 1440x3000, visually scaled to 0.28

                        Lock/unlock ONLY toggles overflow + pointerEvents.
                        Scale, dimensions, transform-origin stay constant.
                      */}
                      <div style={{ width: '403px', height: '840px', position: 'relative' }}>
                        <iframe
                          src={website.liveUrl}
                          title={website.name}
                          style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            width: '1440px',
                            height: '3000px',
                            border: 'none',
                            transform: 'scale(0.28)',
                            transformOrigin: 'top left',
                          }}
                          sandbox="allow-scripts allow-same-origin"
                        />
                      </div>
                    </div>
                  ) : website.thumbnail ? (
                    /* Uploaded thumbnail */
                    <img
                      src={website.thumbnail}
                      alt={website.name}
                      className="w-full h-full object-cover object-top"
                    />
                  ) : (
                    /* Fallback placeholder */
                    <div className="absolute inset-0 flex items-center justify-center">
                      <div className={`w-20 h-20 ${industry.color} rounded-2xl flex items-center justify-center text-3xl shadow-lg`}>
                        {industry.icon}
                      </div>
                    </div>
                  )}

                  {/* Hover overlay - only show when locked */}
                  {!isUnlocked && (
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-4">
                      {/* Website name and info */}
                      <div className="transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                        <h3 className="font-semibold text-white text-base truncate mb-1">{website.name}</h3>
                        <div className="flex items-center gap-2 flex-wrap mb-3">
                          <span className={`px-2 py-0.5 ${industry.color} rounded text-white text-xs font-medium`}>
                            {industry.icon} {industry.name}
                          </span>
                          <span className="text-white/80 text-xs">
                            {website.pages.length} page{website.pages.length !== 1 ? 's' : ''}
                          </span>
                          {website.linkedSnapshotIds.length > 0 && (
                            <span className="text-gold-300 text-xs flex items-center gap-1">
                              <Layers size={12} />
                              {website.linkedSnapshotIds.length} snapshot{website.linkedSnapshotIds.length !== 1 ? 's' : ''}
                            </span>
                          )}
                        </div>
                      </div>

                      {/* Quick action icons */}
                      <div className="flex items-center gap-2 transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300 delay-75">
                        {website.liveUrl && (
                          <a
                            href={website.liveUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                            onClick={(e) => e.stopPropagation()}
                            className="p-2 bg-white/20 hover:bg-white/30 rounded-lg backdrop-blur-sm transition-colors"
                            title="Open Live Site"
                          >
                            <ExternalLink size={16} className="text-white" />
                          </a>
                        )}
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            setEditingWebsite(website);
                            setWebsiteForm({
                              name: website.name,
                              liveUrl: website.liveUrl,
                              industry: website.industry,
                              notes: website.notes || '',
                              previewMode: website.previewMode || 'live',
                              thumbnail: website.thumbnail || '',
                            });
                            setShowAddModal(true);
                          }}
                          className="p-2 bg-white/20 hover:bg-white/30 rounded-lg backdrop-blur-sm transition-colors"
                          title="Edit"
                        >
                          <Edit3 size={16} className="text-white" />
                        </button>
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            handleDuplicateWebsite(website);
                          }}
                          className="p-2 bg-white/20 hover:bg-white/30 rounded-lg backdrop-blur-sm transition-colors"
                          title="Duplicate"
                        >
                          <Copy size={16} className="text-white" />
                        </button>
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            setWebsiteToDelete(website);
                            setShowDeleteConfirm(true);
                          }}
                          className="p-2 bg-white/20 hover:bg-red-500/50 rounded-lg backdrop-blur-sm transition-colors"
                          title="Delete"
                        >
                          <Trash2 size={16} className="text-white" />
                        </button>
                      </div>
                    </div>
                  )}

                  {/* Lock/Unlock button - always visible in bottom right for live previews */}
                  {useLivePreview && (
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleCardLock(website.id);
                      }}
                      className={`absolute bottom-3 right-3 p-2 rounded-lg shadow-lg transition-all z-10 ${
                        isUnlocked
                          ? 'bg-gold-500 text-white hover:bg-gold-600'
                          : 'bg-white/90 dark:bg-dark-card/90 text-gray-600 dark:text-dark-muted hover:bg-white dark:hover:bg-dark-card'
                      }`}
                      title={isUnlocked ? 'Lock scroll (click to lock)' : 'Unlock scroll (hover to scroll through site)'}
                    >
                      {isUnlocked ? <Unlock size={16} /> : <Lock size={16} />}
                    </button>
                  )}
                </div>

                {/* Card footer - minimal info */}
                <div
                  className="p-3 border-t border-gray-100 dark:border-dark-border cursor-pointer hover:bg-gray-50 dark:hover:bg-dark-hover transition-colors"
                  onClick={() => setSelectedWebsite(website)}
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 min-w-0">
                      <span className={`w-2 h-2 rounded-full ${industry.color} flex-shrink-0`} />
                      <span className="font-medium text-gray-800 dark:text-dark-text text-sm truncate">{website.name}</span>
                    </div>
                    <span className="text-xs text-gray-400 dark:text-dark-muted flex-shrink-0">
                      {website.pages.length} pg{website.pages.length !== 1 ? 's' : ''}
                    </span>
                  </div>
                </div>
              </div>
            );
          })}

          {/* Add website card - dashed border style */}
          <button
            onClick={() => {
              setEditingWebsite(null);
              setWebsiteForm({ name: '', liveUrl: '', industry: 'other', notes: '', previewMode: 'live', thumbnail: '' });
              setShowAddModal(true);
            }}
            className="group relative rounded-xl border-2 border-dashed border-gray-300 dark:border-dark-border hover:border-gold-400 dark:hover:border-gold-500 bg-gray-50/50 dark:bg-dark-elevated/50 flex items-center justify-center transition-all duration-300 hover:bg-gold-50/50 dark:hover:bg-gold-900/10 min-h-[280px]"
          >
            <div className="flex flex-col items-center gap-3">
              <div className="w-14 h-14 rounded-full bg-gray-200 dark:bg-dark-border group-hover:bg-gold-100 dark:group-hover:bg-gold-900/30 flex items-center justify-center transition-colors">
                <Plus size={28} className="text-gray-400 group-hover:text-gold-600 transition-colors" />
              </div>
              <span className="text-sm text-gray-400 group-hover:text-gold-600 font-medium transition-colors">Add Website</span>
            </div>
          </button>
        </div>
      )}

      {/* Add/Edit Website Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={() => setShowAddModal(false)}>
          <div
            className="bg-white dark:bg-dark-card rounded-xl shadow-xl w-full max-w-lg mx-4"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-dark-border">
              <h3 className="font-semibold text-gray-800 dark:text-dark-text">
                {editingWebsite ? 'Edit Website' : 'Add Website to Library'}
              </h3>
              <button
                onClick={() => setShowAddModal(false)}
                className="p-1 text-gray-400 hover:text-gray-600"
              >
                <X size={20} />
              </button>
            </div>
            <div className="p-4 space-y-4 max-h-[70vh] overflow-y-auto">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Website Name *</label>
                <input
                  type="text"
                  value={websiteForm.name}
                  onChange={(e) => setWebsiteForm({ ...websiteForm, name: e.target.value })}
                  placeholder="e.g., Plumber Pro"
                  className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Live URL</label>
                <input
                  type="url"
                  value={websiteForm.liveUrl}
                  onChange={(e) => setWebsiteForm({ ...websiteForm, liveUrl: e.target.value })}
                  placeholder="https://example.webflow.io"
                  className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
                />
                <p className="text-xs text-gray-500 mt-1">The live or staging URL for this website</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Industry</label>
                <select
                  value={websiteForm.industry}
                  onChange={(e) => setWebsiteForm({ ...websiteForm, industry: e.target.value as WebsiteIndustry })}
                  className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
                >
                  {WEBSITE_INDUSTRIES.map(ind => (
                    <option key={ind.id} value={ind.id}>{ind.icon} {ind.name}</option>
                  ))}
                </select>
              </div>

              {/* Preview Mode Toggle */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-2">Card Preview</label>
                <div className="flex gap-2">
                  <button
                    type="button"
                    onClick={() => setWebsiteForm({ ...websiteForm, previewMode: 'live' })}
                    className={`flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg border transition-all ${
                      websiteForm.previewMode === 'live'
                        ? 'border-gold-500 bg-gold-50 dark:bg-gold-900/20 text-gold-700 dark:text-gold-400'
                        : 'border-gray-200 dark:border-dark-border text-gray-600 dark:text-dark-muted hover:border-gray-300'
                    }`}
                  >
                    <Globe size={18} />
                    <span className="text-sm font-medium">Live Preview</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setWebsiteForm({ ...websiteForm, previewMode: 'thumbnail' })}
                    className={`flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg border transition-all ${
                      websiteForm.previewMode === 'thumbnail'
                        ? 'border-gold-500 bg-gold-50 dark:bg-gold-900/20 text-gold-700 dark:text-gold-400'
                        : 'border-gray-200 dark:border-dark-border text-gray-600 dark:text-dark-muted hover:border-gray-300'
                    }`}
                  >
                    <ImageIcon size={18} />
                    <span className="text-sm font-medium">Upload Image</span>
                  </button>
                </div>
                <p className="text-xs text-gray-500 mt-1.5">
                  {websiteForm.previewMode === 'live'
                    ? 'Card will show a live iframe preview of the website. You can scroll through when unlocked.'
                    : 'Upload a custom screenshot image for the card preview.'}
                </p>
              </div>

              {/* Thumbnail Upload - only show when thumbnail mode is selected */}
              {websiteForm.previewMode === 'thumbnail' && (
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Thumbnail Image</label>
                  <div className="space-y-2">
                    <input
                      type="url"
                      value={websiteForm.thumbnail}
                      onChange={(e) => setWebsiteForm({ ...websiteForm, thumbnail: e.target.value })}
                      placeholder="https://example.com/screenshot.png"
                      className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent"
                    />
                    <div className="flex items-center gap-2">
                      <span className="text-xs text-gray-400">or</span>
                      <label className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 dark:bg-dark-elevated hover:bg-gray-200 dark:hover:bg-dark-border rounded-lg cursor-pointer transition-colors">
                        <Upload size={14} className="text-gray-500" />
                        <span className="text-xs font-medium text-gray-600 dark:text-dark-muted">Upload File</span>
                        <input
                          type="file"
                          accept="image/*"
                          className="hidden"
                          onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) {
                              const reader = new FileReader();
                              reader.onload = (event) => {
                                setWebsiteForm({ ...websiteForm, thumbnail: event.target?.result as string });
                              };
                              reader.readAsDataURL(file);
                            }
                          }}
                        />
                      </label>
                    </div>
                    {/* Thumbnail preview */}
                    {websiteForm.thumbnail && (
                      <div className="relative mt-2 rounded-lg overflow-hidden border border-gray-200 dark:border-dark-border">
                        <img
                          src={websiteForm.thumbnail}
                          alt="Thumbnail preview"
                          className="w-full h-32 object-cover object-top"
                        />
                        <button
                          type="button"
                          onClick={() => setWebsiteForm({ ...websiteForm, thumbnail: '' })}
                          className="absolute top-2 right-2 p-1 bg-black/50 hover:bg-black/70 rounded-full text-white transition-colors"
                        >
                          <X size={14} />
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              )}

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-dark-text mb-1">Notes (optional)</label>
                <textarea
                  value={websiteForm.notes}
                  onChange={(e) => setWebsiteForm({ ...websiteForm, notes: e.target.value })}
                  placeholder="Any notes about this website..."
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-200 dark:border-dark-border rounded-lg bg-white dark:bg-dark-elevated text-gray-800 dark:text-dark-text focus:ring-2 focus:ring-gold-500 focus:border-transparent resize-none"
                />
              </div>
            </div>
            <div className="flex gap-3 p-4 border-t border-gray-200 dark:border-dark-border">
              <button
                onClick={() => setShowAddModal(false)}
                className="flex-1 px-4 py-2 border border-gray-200 dark:border-dark-border rounded-lg text-gray-600 hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={editingWebsite ? handleUpdateWebsite : handleAddWebsite}
                className="flex-1 px-4 py-2 bg-gold-500 text-white rounded-lg hover:bg-gold-600 transition-colors font-medium"
              >
                {editingWebsite ? 'Save Changes' : 'Add Website'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Delete Website Confirmation */}
      {showDeleteConfirm && websiteToDelete && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={() => setShowDeleteConfirm(false)}>
          <div
            className="bg-white dark:bg-dark-card rounded-xl shadow-xl w-full max-w-sm mx-4 p-5"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="text-center mb-4">
              <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-3">
                <Trash2 size={24} className="text-red-500" />
              </div>
              <h3 className="font-semibold text-gray-800 dark:text-dark-text mb-1">Delete Website?</h3>
              <p className="text-sm text-gray-500">
                Are you sure you want to remove "{websiteToDelete.name}" from the library? This action cannot be undone.
              </p>
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => setShowDeleteConfirm(false)}
                className="flex-1 px-4 py-2 border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleDeleteWebsite}
                className="flex-1 px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors font-medium"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Quick Preview Modal */}
      {showPreviewModal && previewWebsite && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50" onClick={() => setShowPreviewModal(false)}>
          <div
            className="bg-white dark:bg-dark-card rounded-xl shadow-2xl w-full max-w-5xl max-h-[90vh] mx-4 flex flex-col overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-dark-border bg-gray-50 dark:bg-dark-elevated">
              <div className="flex items-center gap-3">
                <Globe size={20} className="text-gray-500" />
                <div>
                  <h3 className="font-semibold text-gray-800 dark:text-dark-text">{previewWebsite.name}</h3>
                  <p className="text-xs text-gray-500">{previewWebsite.liveUrl}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => {
                    setShowPreviewModal(false);
                    setSelectedWebsite(previewWebsite);
                  }}
                  className="flex items-center gap-1.5 px-3 py-1.5 border border-gray-200 dark:border-dark-border rounded-lg text-sm font-medium text-gray-700 dark:text-dark-text hover:bg-gray-100 transition-colors"
                >
                  View Details
                </button>
                {previewWebsite.liveUrl && (
                  <a
                    href={previewWebsite.liveUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-1.5 bg-gold-500 text-white px-3 py-1.5 rounded-lg text-sm font-medium hover:bg-gold-600 transition-colors"
                  >
                    <ExternalLink size={14} />
                    Open Live Site
                  </a>
                )}
                <button
                  onClick={() => setShowPreviewModal(false)}
                  className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                  <X size={20} />
                </button>
              </div>
            </div>
            {/* Preview iframe */}
            <div className="flex-1 bg-gray-100 dark:bg-dark-bg overflow-hidden">
              {previewWebsite.liveUrl ? (
                <iframe
                  src={previewWebsite.liveUrl}
                  className="w-full h-full min-h-[500px] border-0"
                  title={`Preview: ${previewWebsite.name}`}
                  sandbox="allow-scripts allow-same-origin"
                />
              ) : (
                <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-center p-8">
                  <div className="w-16 h-16 bg-gray-200 rounded-full flex items-center justify-center mb-4">
                    <Globe size={32} className="text-gray-400" />
                  </div>
                  <h4 className="text-lg font-medium text-gray-700 dark:text-dark-text mb-2">No Live URL Set</h4>
                  <p className="text-sm text-gray-500 max-w-md">
                    Add a live URL to preview this website
                  </p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
